const obj2form = (obj) => {
  const fd = new FormData();
  for (const k in obj) {
    const v = obj[k];
    if (v instanceof File) {
      fd.append(k, v, v.name);
    } else if (v instanceof Blob) {
      fd.append(k, v);
    } else if (typeof v === "string") {
      fd.append(k, v);
    }
  }
  return fd;
};
const defaultHeaders = {
  "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36 Edg/125.0.0.0",
  origin: `https://github.com`,
  referer: "https://github.com/"
};
const acceptMimeMap = {
  // File types that are acceptable in any context
  svg: "image/svg+xml",
  gif: "image/gif",
  jpg: "image/jpeg",
  jpeg: "image/jpeg",
  png: "image/png",
  mov: "video/quicktime",
  mp4: "video/mp4",
  webm: "video/webm",
  // File types that are only acceptable when there is a target repo to upload to, include the upper list
  cpuprofile: "application/json",
  csv: "text/csv",
  dmp: "application/octet-stream",
  docx: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  fodg: "application/vnd.oasis.opendocument.graphics-flat-xml",
  fodp: "application/vnd.oasis.opendocument.presentation-flat-xml",
  fods: "application/vnd.oasis.opendocument.spreadsheet-flat-xml",
  fodt: "application/vnd.oasis.opendocument.text-flat-xml",
  gz: "application/gzip",
  json: "application/json",
  jsonc: "application/json",
  log: "text/plain",
  md: "text/markdown",
  odf: "application/vnd.oasis.opendocument.formula",
  odg: "application/vnd.oasis.opendocument.graphics",
  odp: "application/vnd.oasis.opendocument.presentation",
  ods: "application/vnd.oasis.opendocument.spreadsheet",
  odt: "application/vnd.oasis.opendocument.text",
  patch: "text/x-diff",
  pdf: "application/pdf",
  pptx: "application/vnd.openxmlformats-officedocument.presentationml.presentation",
  tgz: "application/gzip",
  txt: "text/plain",
  xls: "application/vnd.ms-excel",
  xlsx: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
  zip: "application/x-zip-compressed"
};
class UploadError extends Error {
  constructor(message, response, options) {
    super(message, options);
    this.response = response;
  }
}
const filterNotNullObject = (obj) => {
  const newObj = {};
  for (const k in obj) {
    const v = obj[k];
    if (v !== undefined && v !== null) {
      newObj[k] = v;
    }
  }
  return newObj;
};

const uploadPoliciesAssets = async (options) => {
  const { cookie, fetch = globalThis.fetch, repositoryId } = options;
  const fileExt = options.file.name.substring(
    options.file.name.lastIndexOf(".") + 1
  );
  const content_type = acceptMimeMap[fileExt];
  if (!content_type) {
    throw new Error(`not support file type ${fileExt}`);
  }
  const file = options.file.type ? options.file : new File([options.file], options.file.name, {
    type: content_type
  });
  const formData = new FormData();
  if (repositoryId) {
    formData.append("repository_id", String(repositoryId));
  }
  formData.append("name", file.name);
  formData.append("size", file.size.toString());
  formData.append("content_type", file.type);
  const policiesResp = await fetch(
    `https://github.com/upload/policies/assets`,
    {
      method: "POST",
      body: formData,
      headers: filterNotNullObject({
        ...defaultHeaders,
        cookie,
        "GitHub-Verified-Fetch": "true",
        "X-Requested-With": "XMLHttpRequest"
      })
    }
  ).then(async (r) => {
    if (!r.ok) {
      throw new UploadError(`failed upload policies assets`, r);
    }
    return r.json();
  });
  await fetch(policiesResp.upload_url, {
    method: `POST`,
    body: obj2form({
      ...policiesResp.form,
      file
    }),
    headers: filterNotNullObject({
      authenticity_token: policiesResp.same_origin ? policiesResp.upload_authenticity_token : undefined,
      ...defaultHeaders,
      ...policiesResp.header,
      cookie
    })
  }).then(async (r) => {
    if (!r.ok) {
      throw new UploadError(`failed upload to s3`, r);
    }
  });
  await fetch(
    new URL(policiesResp.asset_upload_url, `https://github.com/`).href,
    {
      method: `PUT`,
      body: obj2form({
        authenticity_token: policiesResp.asset_upload_authenticity_token
      }),
      headers: filterNotNullObject({
        ...defaultHeaders,
        cookie,
        Accept: "application/json",
        "X-Requested-With": "XMLHttpRequest"
      })
    }
  ).then(async (r) => {
    if (!r.ok) {
      throw new UploadError(`failed check authenticity upload`, r);
    }
  });
  return policiesResp.asset;
};

export { UploadError, acceptMimeMap, uploadPoliciesAssets };
